previewCss:
.darma-loader-darma-custom-637 {color: var(--loader-color, #e11d48);
  --loader-secondary-color: var(--loader-secondary-color, #fb7185);
  --loader-bg: var(--loader-bg, #ffffff);
   width: 90px;
   height: 14px;
   box-shadow: 0 3px 0 currentColor;
   display: grid;
}
.darma-loader-darma-custom-637:before, .darma-loader-darma-custom-637:after {
  content: "";
   grid-area: 1/1;
   background: radial-gradient(circle closest-side,var(--c,var(--loader-color, #e11d48)) 92%,#0000) 0 0/calc(100%/4) 100%;
   animation: darma-loader-darma-custom-637-l4 1s infinite linear;
}
.darma-loader-darma-custom-637:after {
  --c: currentColor;
   background-color: currentColor;
   box-shadow: 0 -2px 0 0 currentColor;
   clip-path: inset(-2px calc(50% - 10px));
}
@keyframes darma-loader-darma-custom-637-l4  {
  100% {background-position: calc(100%/3) 0}
}

